    @RustCleanup("Remove in V16.") // Not in libAnki
    fun findOneCardByNote(query: String, order: SortOrder = SortOrder.NoOrdering()): List<CardId> {
        // This function shouldn't exist and CardBrowser should be modified to use Notes,
        // so not much effort was expended here

        val noteIds = findNotes(query, order)
        if (noteIds.isEmpty()) {
            return emptyList()
        }

        // Create a map to preserve the order of noteIds
        val noteOrderMap = noteIds.withIndex().associate { it.value to it.index }

        // select the card with the lowest `ord` to show
        val cardIds = db.queryLongList(
            """
SELECT c.id
FROM (
  SELECT nid, MIN(ord) AS ord
  FROM cards
  WHERE nid IN ${Utils.ids2str(noteIds)} 
  GROUP BY nid
) AS card_with_min_ord
JOIN cards AS c ON card_with_min_ord.nid = c.nid AND card_with_min_ord.ord = c.ord;
            """.trimMargin()
        )

        // Re-sort the card IDs based on the original note order
        // First, get the note ID for each card ID
        val cardToNoteMap = mutableMapOf<CardId, Long>()
        val cardIdsStr = Utils.ids2str(cardIds)
        if (cardIds.isNotEmpty()) {
            db.query("SELECT id, nid FROM cards WHERE id IN $cardIdsStr").use { cursor ->
                while (cursor.moveToNext()) {
                    cardToNoteMap[cursor.getLong(0)] = cursor.getLong(1)
                }
            }
        }

        // Sort card IDs by the original note order
        return cardIds.sortedBy { cardId ->
            val nid = cardToNoteMap[cardId] ?: Long.MAX_VALUE
            noteOrderMap[nid] ?: Int.MAX_VALUE
        }
    }"}

