package com.ichi2.anki

import androidx.test.ext.junit.runners.AndroidJUnit4
import com.ichi2.anki.model.CardsOrNotes
import com.ichi2.anki.model.SortType
import com.ichi2.testutils.JvmTest
import org.junit.Assert.assertEquals
import org.junit.Test
import org.junit.runner.RunWith

@RunWith(AndroidJUnit4::class)
class CardBrowserSortOrderTest : JvmTest() {

    @Test
    fun testSortOrderPersistsForNotesMode() = runTest {
        val col = col
        val preferences = targetContext.sharedPrefs()

        // Set sort order for notes mode
        val sortType = SortType.NOTE_MODIFICATION_TIME
        sortType.save(col.config, preferences, CardsOrNotes.NOTES)
        col.config.set("browserNoteSortBackwards", true)

        // Verify it was saved to the correct config keys
        assertEquals("noteMod", col.config.get<String>("noteSortType"))
        assertEquals(true, col.config.get<Boolean>("browserNoteSortBackwards"))

        // Verify cards mode config is not affected
        val cardsSortType = SortType.fromCol(col.config, preferences, CardsOrNotes.CARDS)
        assertEquals(SortType.NO_SORTING, cardsSortType)
    }

    @Test
    fun testSortOrderPersistsForCardsMode() = runTest {
        val col = col
        val preferences = targetContext.sharedPrefs()

        // Set sort order for cards mode
        val sortType = SortType.DUE_TIME
        sortType.save(col.config, preferences, CardsOrNotes.CARDS)
        col.config.set("sortBackwards", true)

        // Verify it was saved to the correct config keys
        assertEquals("cardDue", col.config.get<String>("sortType"))
        assertEquals(true, col.config.get<Boolean>("sortBackwards"))

        // Verify notes mode config is not affected
        val notesSortType = SortType.fromCol(col.config, preferences, CardsOrNotes.NOTES)
        assertEquals(SortType.NO_SORTING, notesSortType)
    }

    @Test
    fun testSwitchingBetweenCardsModeAndNotesMode() = runTest {
        val col = col
        val preferences = targetContext.sharedPrefs()

        // Set different sort orders for cards and notes
        SortType.DUE_TIME.save(col.config, preferences, CardsOrNotes.CARDS)
        col.config.set("sortBackwards", false)

        SortType.CREATED_TIME.save(col.config, preferences, CardsOrNotes.NOTES)
        col.config.set("browserNoteSortBackwards", true)

        // Verify cards mode loads correct sort order
        val cardsSortType = SortType.fromCol(col.config, preferences, CardsOrNotes.CARDS)
        assertEquals(SortType.DUE_TIME, cardsSortType)
        assertEquals(false, col.config.get<Boolean>("sortBackwards"))

        // Verify notes mode loads correct sort order
        val notesSortType = SortType.fromCol(col.config, preferences, CardsOrNotes.NOTES)
        assertEquals(SortType.CREATED_TIME, notesSortType)
        assertEquals(true, col.config.get<Boolean>("browserNoteSortBackwards"))
    }

    @Test
    fun testDefaultSortOrderForNewNotesMode() = runTest {
        val col = col
        val preferences = targetContext.sharedPrefs()

        // Don't set any sort order for notes mode
        // Verify default is NO_SORTING when config key doesn't exist
        val notesSortType = SortType.fromCol(col.config, preferences, CardsOrNotes.NOTES)
        assertEquals(SortType.NO_SORTING, notesSortType)
    }
}
"}

